import { BarLabelOverlay } from './BarLabelOverlay.js';
import { plotLayout } from '../../../../core/components/chart-grid/ChartGrid.sty.js';
import { zIndicesXYChartAreas } from '../../../constants/xy-chart-z-index-areas.js';
import { useBarData } from '../../../hooks/useBarData.js';
import { useXYChartScales } from '../../../hooks/useXYChartScales.js';

/**
 * Chart-level wrapper that mounts the HTML bar labels for every bar series
 * with `hasLabels === true`. Rendered as a sibling of the canvas plot inside
 * `<ChartGrid.PlotArea>` because HTML cannot live inside `<canvas>` — see
 * `./BarDisplay.tsx` for the canvas-paint counterpart.
 */
export function BarLabelLayout() {
  const axisIdToScales = useXYChartScales();
  const { filteredSeriesWithDatapoints, seriesToMetadata } = useBarData();

  const labelSeries = filteredSeriesWithDatapoints.filter(
    (s) => s.hasLabels === true,
  );

  if (labelSeries.length === 0) {
    return null;
  }

  // z-index above the canvas (`plot` layer) so the HTML labels render on top
  // of the 0.8-opacity bar fills — otherwise the canvas paints over the
  // labels and blends them with the bar color.
  return (
    <div
      className={plotLayout}
      style={{
        zIndex: zIndicesXYChartAreas.plot + 1,
        pointerEvents: 'none',
      }}
    >
      {labelSeries.map((series) => {
        const metadata = seriesToMetadata.get(series);
        if (!metadata) {
          return null;
        }
        return (
          <BarLabelOverlay
            key={series.id}
            axisIdToScales={axisIdToScales}
            series={series}
            metadata={metadata}
          />
        );
      })}
    </div>
  );
}

BarLabelLayout['displayName'] = 'BarLabelLayout';
